mapper.select:
SELECT 
    n.*,
    COALESCE(nr.read_status, 0) as isRead
FROM notice n
LEFT JOIN user u ON u.user_id = #{currentUserId}
LEFT JOIN notice_read nr ON n.notice_id = nr.notice_id AND nr.residence_id = u.residence_id


        AND n.title LIKE CONCAT('%', #{title}, '%')


        AND n.status = #{status}


        AND n.publisher_id = #{publisherId}


        AND n.publisher_type = #{publisherType}



            AND nr.read_status = 1


            AND (nr.read_status IS NULL OR nr.read_status = 0)



ORDER BY n.publish_time DESC

mapper.update:
UPDATE notice
SET status = #{status}
WHERE notice_id = #{noticeId}

mapper.select:
SELECT nr.notice_id AS noticeId, nr.residence_id AS residenceId, nr.read_status AS readStatus, nr.read_time AS readTime, u.user_id AS userId, u.nickname, u.avatar_url AS avatarUrl, u.building_no AS buildingNo, u.unit_no AS unitNo, u.room_no AS roomNo, u.phone FROM notice_read nr LEFT JOIN user u ON u.residence_id = nr.residence_id WHERE nr.notice_id = #{noticeId} AND nr.read_status = #{readStatus}
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR nr.residence_id LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY u.building_no, u.unit_no, u.room_no
